// Limpiamos los datos para que PostgreSQL no se queje
const item = $input.first().json;

return [{
  json: {
    titulo: item.titulo || 'Sin título',
    precio: parseFloat(item.precio) || 0,
    moneda: item.moneda || 'USD',
    url_original: item.link || item.url_original,
    barrio: item.barrio || '',
    dormitorios: parseInt(item.dormitorios) || 0,
    banios: parseInt(item.banios) || 0,
    imagen_principal: item.imagen || '',
    tipo_operacion: item.tipo_operacion || 'alquiler',
    fuente: 'meli_hunter_local',
    garaje: !!item.garaje,
    piscina: !!item.piscina
  }
}];
